const INCLUSIONS = {
  tier1: `✨ *What's Included (Starts at ₱2,499):*\n\n📷 Unlimited shots with enhanced photos\n⏱ 2 hours of photo & video coverage\n➕ Additional ₱500/hour if needed\n\n🚗 *Transportation Fees:*\n• 14km and below — FREE\n• 15km–20km — +₱400\n• 21km–28km — +₱700\n• 29km–35km — +₱1,000\n• 36km and above — +₱1,500\n\n🎬 Video highlights available for +₱2,999`,
  tier2: `✨ *What's Included (Starts at ₱3,499):*\n\n📷 Unlimited shots with enhanced photos\n⏱ 2 hours of photo & video coverage\n➕ Additional ₱500/hour if needed\n\n🚗 *Transportation Fees:*\n• 14km and below — FREE\n• 15km–20km — +₱400\n• 21km–28km — +₱700\n• 29km–35km — +₱1,000\n• 36km and above — +₱1,500\n\n🎬 Video highlights available for +₱2,999`,
};

// ─── HELPERS ─────────────────────────────────────────────────────────────────

function getImageUrl(imgKey) {
  return IMAGES[imgKey] || IMAGES['OTHERS'];
}

function getTierForOccasion(occasionId) {
  for (const [tierId, tier] of Object.entries(TIERS)) {
    if (tier.occasions.find(o => o.id === occasionId)) return tierId;
  }
  return null;
}

// ─── SEND FUNCTIONS ───────────────────────────────────────────────────────────

async function sendMessage(psid, message) {
  await axios.post(
    `https://graph.facebook.com/v19.0/me/messages?access_token=${PAGE_ACCESS_TOKEN}`,
    { recipient: { id: psid }, message }
  );
}

async function sendText(psid, text) {
  await sendMessage(psid, { text });
}

async function sendTierButtons(psid) {
  await sendText(psid, `👋 Hi! Welcome to *Framepoint Photography* 📸\n\nYour moments, perfectly covered. Let's get started!\n\nWhich package are you interested in?`);
  await sendMessage(psid, {
    attachment: {
      type: 'template',
      payload: {
        template_type: 'button',
        text: '💰 Choose your package:',
        buttons: [
          { type: 'postback', title: '📸 Starts at ₱2,499', payload: 'SELECT_TIER_tier1' },
          { type: 'postback', title: '🎬 Starts at ₱3,499', payload: 'SELECT_TIER_tier2' },
        ],
      },
    },
  });
}

async function sendOccasionCards(psid, tierId) {
  const tier = TIERS[tierId];
  if (!tier) return;

  await sendText(psid, `Great choice! 🎉 Here are the occasions covered under the *${tier.price}* package:\n\nSelect your occasion below 👇`);

  const elements = tier.occasions.map(occasion => ({
    title: occasion.label,
    subtitle: occasion.subtitle,
    image_url: getImageUrl(occasion.imgKey),
    buttons: [
      {
        type: 'postback',
        title: `Book ${occasion.label}`,
        payload: `SELECT_OCCASION_${occasion.id}`,
      },
    ],
  }));

  await sendMessage(psid, {
    attachment: {
      type: 'template',
      payload: {
        template_type: 'generic',
        elements,
      },
    },
  });
}

async function sendInclusions(psid, occasionId) {
  const tierId = getTierForOccasion(occasionId);
  if (!tierId) return;

  const tier = TIERS[tierId];
  const occasion = tier.occasions.find(o => o.id === occasionId);

  await sendText(psid, `📋 Here are the details for your *${occasion.label}* booking:\n\n${INCLUSIONS[tierId]}`);

  await sendMessage(psid, {
    attachment: {
      type: 'template',
      payload: {
        template_type: 'button',
        text: `Ready to book your ${occasion.label} shoot? 🎉`,
        buttons: [
          {
            type: 'web_url',
            title: '📅 Book Now',
            url: `${BOOKING_URL}?occasion=${occasionId}`,
            webview_height_ratio: 'full',
          },
          {
            type: 'postback',
            title: '🔄 Choose Another',
            payload: `SELECT_TIER_${tierId}`,
          },
          {
            type: 'postback',
            title: '🏠 Start Over',
            payload: 'GET_STARTED',
          },
        ],
      },
    },
  });
}

// ─── WEBHOOK ─────────────────────────────────────────────────────────────────

app.get('/webhook', (req, res) => {
  if (req.query['hub.mode'] === 'subscribe' && req.query['hub.verify_token'] === VERIFY_TOKEN) {
    res.status(200).send(req.query['hub.challenge']);
  } else {
    res.sendStatus(403);
  }
});

app.post('/webhook', async (req, res) => {
  res.sendStatus(200);
  const body = req.body;
  if (body.object !== 'page') return;

  for (const entry of body.entry) {
    for (const event of entry.messaging) {
      const psid = event.sender.id;

      try {
        // Postback handler
        if (event.postback) {
          const payload = event.postback.payload;

          if (payload === 'GET_STARTED' || payload === 'RESTART') {
            await sendTierButtons(psid);
          } else if (payload.startsWith('SELECT_TIER_')) {
            const tierId = payload.replace('SELECT_TIER_', '');
            await sendOccasionCards(psid, tierId);
          } else if (payload.startsWith('SELECT_OCCASION_')) {
            const occasionId = payload.replace('SELECT_OCCASION_', '');
            await sendInclusions(psid, occasionId);
          }
        }

        // Text message handler
        if (event.message && event.message.text) {
          const text = event.message.text.toLowerCase().trim();
          if (['hi', 'hello', 'hey', 'start', 'book', 'booking'].some(k => text.includes(k))) {
            await sendTierButtons(psid);
          } else {
            await sendMessage(psid, {
              attachment: {
                type: 'template',
                payload: {
                  template_type: 'button',
                  text: `Hi! 👋 I'm the Framepoint Photography bot.\n\nTap below to start booking your shoot! 📸`,
                  buttons: [
                    { type: 'postback', title: '📸 View Packages', payload: 'GET_STARTED' },
                  ],
                },
              },
            });
          }
        }
      } catch (err) {
        console.error('Error handling event:', err.message);
      }
    }
  }
});

const PORT = process.env.PORT || 3000;
app.listen(PORT, () => console.log(`Framepoint bot running on port ${PORT}`));
